/* Evidence: cmem-worked-cmem-cleanup-error-paths-2 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 2978; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


static int worked_cmem_cleanup_error_paths_2(int fail_stage, int released[3]) {
  int acquired = 0;
  int index;
  for (index = 0; index < 3; ++index) {
    if (fail_stage == index) break;
    acquired += 1;
  }
  while (acquired > 0) {
    acquired -= 1;
    released[acquired] = 6 + acquired;
  }
  return fail_stage < 3 ? 0 : 1;
}

int main(void) {
  int released[3] = { 0, 0, 0 };
  int completed = worked_cmem_cleanup_error_paths_2(3, released);
  int invariant = completed && released[2] == 8 && released[0] == 6;
  printf("cleanup first=%d last=%d invariant=%d\n", released[2], released[0], invariant);
  return invariant ? 0 : 1;
}

